package com.example.deeplink

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity

class DeepLinkActivity : AppCompatActivity() {
    
    companion object {
        const val SCHEME = "myapp"
        const val HOST_PROFILE = "profile"
        const val HOST_PAYMENT = "payment"
        const val EXTRA_USER_ID = "extra_user_id"
        const val EXTRA_PAYMENT_ACTION = "extra_payment_action"
    }
    
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        val data: Uri? = intent?.data
        
        if (data != null && data.scheme == SCHEME) {
            handleDeepLink(data)
        } else {
            navigateToMain()
        }
        
        finish()
    }
    
    private fun handleDeepLink(uri: Uri) {
        val host = uri.host
        val pathSegments = uri.pathSegments
        
        when (host) {
            HOST_PROFILE -> handleProfileDeepLink(pathSegments)
            HOST_PAYMENT -> handlePaymentDeepLink(pathSegments)
            else -> navigateToMain()
        }
    }
    
    private fun handleProfileDeepLink(pathSegments: List<String>) {
        if (pathSegments.isNotEmpty()) {
            val userId = pathSegments[0]
            val intent = Intent(this, ProfileActivity::class.java).apply {
                putExtra(EXTRA_USER_ID, userId)
                flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
            }
            startActivity(intent)
        } else {
            navigateToMain()
        }
    }
    
    private fun handlePaymentDeepLink(pathSegments: List<String>) {
        if (pathSegments.isNotEmpty()) {
            val action = pathSegments[0]
            val intent = Intent(this, PaymentActivity::class.java).apply {
                putExtra(EXTRA_PAYMENT_ACTION, action)
                flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
            }
            startActivity(intent)
        } else {
            navigateToMain()
        }
    }
    
    private fun navigateToMain() {
        val intent = Intent(this, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        }
        startActivity(intent)
    }
}

